Here are comprehensive unit tests for the `deep_get` function using pytest style, covering happy path, edge cases, and error cases:

```python
import pytest

def test_deep_get_happy_path():
    """Test basic functionality with nested dictionaries."""
    data = {
        'a': {
            'b': {
                'c': 42
            }
        }
    }
    assert deep_get(data, 'a.b.c') == 42
    assert deep_get(data, 'a.b') == {'c': 42}
    assert deep_get(data, 'a') == {'b': {'c': 42}}

def test_deep_get_with_default():
    """Test returning default value when key doesn't exist."""
    data = {'a': {'b': 1}}
    assert deep_get(data, 'a.c', 'default') == 'default'
    assert deep_get(data, 'x.y.z', 'not_found') == 'not_found'
    assert deep_get(data, 'a.b.c', 0) == 0

def test_deep_get_with_none_default():
    """Test default None behavior."""
    data = {'a': {'b': 1}}
    assert deep_get(data, 'a.c') is None
    assert deep_get(data, 'x.y.z') is None

def test_deep_get_with_empty_keys():
    """Test with empty keys string."""
    data = {'a': 1}
    assert deep_get(data, '') == data
    assert deep_get(data, '', 'default') == data

def test_deep_get_with_single_key():
    """Test with single key (no nesting)."""
    data = {'a': 1, 'b': 2}
    assert deep_get(data, 'a') == 1
    assert deep_get(data, 'b') == 2
    assert deep_get(data, 'c', 'default') == 'default'

def test_deep_get_with_non_dict_intermediate():
    """Test when intermediate value is not a dict."""
    data = {'a': {'b': 1}}
    assert deep_get(data, 'a.b.c') is None
    assert deep_get(data, 'a.b.c', 'default') == 'default'

    data = {'a': 1}
    assert deep_get(data, 'a.b') is None
    assert deep_get(data, 'a.b', 'default') == 'default'

def test_deep_get_with_multiple_levels():
    """Test with multiple nesting levels."""
    data = {
        'level1': {
            'level2': {
                'level3': {
                    'level4': 'found'
                }
            }
        }
    }
    assert deep_get(data, 'level1.level2.level3.level4') == 'found'
    assert deep_get(data, 'level1.level2') == {'level3': {'level4': 'found'}}
    assert deep_get(data, 'level1.level2.level3.level4.level5', 'default') == 'default'

def test_deep_get_with_special_characters():
    """Test with keys containing special characters."""
    data = {
        'a.b': {
            'c.d': 'value'
        }
    }
    assert deep_get(data, 'a.b.c.d') == 'value'

def test_deep_get_with_empty_dict():
    """Test with empty dictionary."""
    assert deep_get({}, 'a.b.c') is None
    assert deep_get({}, 'a.b.c', 'default') == 'default'

def test_deep_get_with_none_input():
    """Test with None input."""
    assert deep_get(None, 'a.b.c') is None
    assert deep_get(None, 'a.b.c', 'default') == 'default'

def test_deep_get_with_non_string_keys():
    """Test with non-string keys parameter."""
    data = {'a': {'b': 1}}
    with pytest.raises(AttributeError):
        deep_get(data, ['a', 'b'])  # keys is a list instead of string
```

These tests cover:
1. Happy path with nested dictionaries
2. Default value behavior
3. Empty keys string
4. Single key access
5. Non-dict intermediate values
6. Multiple nesting levels
7. Special characters in keys
8. Empty dictionary input
9. None input
10. Error case with non-string keys

The tests verify both the positive cases where values are found and the cases where the function should return the default value. The last test checks for proper error handling when the keys parameter isn't a string.

You can run these tests with pytest by saving them in a file (e.g., `test_deep_get.py`) and running `pytest test_deep_get.py` in your terminal.
